args.script:
let images = [];
let currentIndex = -1;

const thumbnails = document.getElementById('thumbnails');
const preview = document.getElementById('preview');
const placeholder = document.getElementById('placeholder');
const filename = document.getElementById('filename');
const imageCount = document.getElementById('image-count');
const prevBtn = document.getElementById('prev');
const nextBtn = document.getElementById('next');

const imageExtensions = ['.jpg', '.jpeg', '.png', '.gif', '.webp', '.bmp', '.svg'];

async function loadFolder() {
  const result = await stuard.pickFolder({ title: 'Select Image Folder' });
  if (result.canceled || !result.filePaths[0]) return;

  const folderPath = result.filePaths[0];

  // Use list_directory tool to get files
  const listResult = await stuard.callTool('list_directory', { path: folderPath });

  if (!listResult.ok) {
    stuard.notify('Error', 'Failed to read folder');
    return;
  }

  // Filter for images
  images = (listResult.entries || [])
    .filter(entry => !entry.isDirectory && imageExtensions.some(ext => entry.name.toLowerCase().endsWith(ext)))
    .map(entry => ({ name: entry.name, path: entry.path }));

  imageCount.textContent = `${images.length} images`;

  // Render thumbnails
  thumbnails.innerHTML = images.map((img, i) => `
    <div class="thumbnail rounded-lg overflow-hidden cursor-pointer bg-slate-800 aspect-square flex items-center justify-center" data-index="${i}">
      <img src="local-file://${img.path.replace(/\\/g, '/')}" class="w-full h-full object-cover" onerror="this.parentElement.innerHTML='<span class=\'text-2xl\'>🖼️</span>'" />
    </div>
  `).join('');

  if (images.length > 0) {
    selectImage(0);
  }
}

function selectImage(index) {
  if (index < 0 || index >= images.length) return;

  currentIndex = index;
  const img = images[index];

  // Update preview
  preview.src = `local-file://${img.path.replace(/\\/g, '/')}`;
  preview.classList.remove('hidden');
  placeholder.classList.add('hidden');
  filename.textContent = img.name;

  // Update thumbnails
  document.querySelectorAll('.thumbnail').forEach((el, i) => {
    el.classList.toggle('active', i === index);
  });

  // Update buttons
  prevBtn.disabled = index === 0;
  nextBtn.disabled = index === images.length - 1;

  // Scroll thumbnail into view
  const thumb = thumbnails.children[index];
  if (thumb) thumb.scrollIntoView({ block: 'nearest' });
}

// Event listeners
document.getElementById('pick-folder').addEventListener('click', loadFolder);

thumbnails.addEventListener('click', (e) => {
  const thumb = e.target.closest('.thumbnail');
  if (thumb) selectImage(parseInt(thumb.dataset.index));
});

prevBtn.addEventListener('click', () => selectImage(currentIndex - 1));
nextBtn.addEventListener('click', () => selectImage(currentIndex + 1));

// Keyboard navigation
document.addEventListener('keydown', (e) => {
  if (e.key === 'ArrowLeft') selectImage(currentIndex - 1);
  if (e.key === 'ArrowRight') selectImage(currentIndex + 1);
  if (e.key === 'Escape') stuard.close();
  if (e.key === 'Home') selectImage(0);
  if (e.key === 'End') selectImage(images.length - 1);
});
